// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

interface ICallback {
    function oracleCallback(uint256 requestId, uint256 result) external;
}

contract Oracle {
    address public owner;
    mapping(uint256 => address) public pendingRequests;
    uint256 public nextRequestId = 1;

    event DataRequested(uint256 indexed requestId, address indexed requester, string query);
    event DataFulfilled(uint256 indexed requestId, uint256 result);

    constructor() {
        owner = msg.sender;
    }

    function requestData(string calldata query) external returns (uint256) {
        uint256 requestId = nextRequestId;
        pendingRequests[requestId] = msg.sender;
        nextRequestId++;
        emit DataRequested(requestId, msg.sender, query);
        return requestId;
    }

    function fulfillRequest(uint256 requestId, uint256 result) external {
        require([[SLOT owner_check]], "only owner");
        address requester = pendingRequests[requestId];
        require([[SLOT exists_check]], "no pending request");
        [[SLOT del_req]]
        [[SLOT cb_call]];
        emit DataFulfilled(requestId, result);
    }
}

contract Client {
    address public oracle;
    uint256 public lastRequestId;
    uint256 public lastResult;
    mapping(uint256 => bool) public fulfilled;

    event ResultReceived(uint256 indexed requestId, uint256 result);

    constructor(address _oracle) {
        oracle = _oracle;
    }

    function makeRequest(string calldata query) external {
        lastRequestId = Oracle(oracle).requestData(query);
    }

    function oracleCallback(uint256 requestId, uint256 result) external {
        require(msg.sender == oracle, "only oracle");
        lastResult = result;
        fulfilled[requestId] = true;
        emit ResultReceived(requestId, result);
    }
}
